--
-- Table structure for table `detalle_alumnos`
--

DROP TABLE IF EXISTS `detalle_alumnos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `detalle_alumnos` (
  `id_detalle` int NOT NULL AUTO_INCREMENT,
  `id_alumno` int NOT NULL,
  `id_convenio` int NOT NULL,
  `ANEXO` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `INICIO_FCT` date DEFAULT NULL,
  `FIN_FCT` date DEFAULT NULL,
  `HORAS_REALIZADAS` int DEFAULT NULL,
  `HORAS_1_SEM` int DEFAULT NULL,
  `HORAS_2_SEM` int DEFAULT NULL,
  `FCT_FINALIZADA` tinyint(1) DEFAULT NULL,
  `RDO_FCT` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `CONVALIDACION_RECIBIDA` tinyint(1) DEFAULT NULL,
  `INSERCION_LABORAL` tinyint(1) DEFAULT NULL,
  `VISITA_REALIZADA` tinyint(1) DEFAULT NULL,
  `FECHA_VISITA` date DEFAULT NULL,
  `ENTREGA_VISITA` date DEFAULT NULL,
  PRIMARY KEY (`id_detalle`),
  KEY `fk_detalle_alumno` (`id_alumno`),
  KEY `fk_detalle_empresa` (`id_convenio`),
  CONSTRAINT `fk_detalle_alumno` FOREIGN KEY (`id_alumno`) REFERENCES `datos_alumnos` (`id_alumno`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_detalle_empresa` FOREIGN KEY (`id_convenio`) REFERENCES `empresas` (`id_convenio`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4147 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
