  `DIRECCION` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `LOCALIDAD` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `CODIGO_POSTAL` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `TXTTE_PUBLICO` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `PERSONA_CONTACTO` text COLLATE utf8mb4_unicode_ci,
  `TUTOR_EMPRESA` text COLLATE utf8mb4_unicode_ci,
  `TELEFONO_1` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `TELEFONO_2` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `EMAIL` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `WEB` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id_convenio`)
) ENGINE=InnoDB AUTO_INCREMENT=1602 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
